def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        penalty = 0.0
        bonus = 0.0
        factor = 1.0
        for j in range(1, 15):
            scale = np.cos(j * ratio) + np.log1p(j)
            if j % 2 == 0:
                scale *= (1 + 0.03 * j)
            else:
                scale *= (1 - 0.02 * j)
            if ratio < 0.1 * j:
                score += (j**3) / (1 + np.exp(-ratio * j)) * scale
            else:
                score += (np.sqrt(j*j) + ratio**2) * scale / (j + 1)
            if (cap * j + j*j) % 6 == 0:
                penalty += (np.tanh(cap / (item + 1)) * j) / (j + 2)
            elif (cap + j*j*j) % 11 == 0:
                penalty -= (np.exp(-ratio * j) + j*0.1)
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff >= 0:
                        if diff % (k+3) == 0:
                            bonus += np.log1p(diff) / (k + 1)
                        else:
                            bonus -= np.sqrt(abs(diff)) / (k + 4)
                    else:
                        bonus -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.75 and j % 3 == 0:
                factor *= 1.07 + 0.015 * j
            elif ratio < 0.15 and j % 4 == 0:
                factor *= 0.85 - 0.008 * j
            if (cap // (j+2)) % 5 == 0:
                penalty += np.sin(j * ratio * np.pi / 2) * 0.4
            if (item + cap) % (j+5) == 0:
                factor *= 1.02
            else:
                factor *= 0.99
        score += penalty * 0.6 + bonus * 1.2
        score *= factor
        if score < 0:
            priorities[i] = -score * (np.log1p(cap * item) + np.sqrt(cap + 1)) * (1 + ratio)
        else:
            if cap > item * 3.5:
                priorities[i] = -score / (np.cbrt(cap) + 1) * (1 + ratio**1.5)
            elif cap < item:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**3)
            else:
                priorities[i] = -score / (np.sqrt(cap) + 2) * np.tanh(ratio * 5)
        if ratio > 0.9:
            priorities[i] *= 1.18
        elif ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if int(cap) % 5 == 0 and ratio > 0.5:
            priorities[i] *= 1.05
    return priorities
